const input = $input.first().json;

function isRecord(value) {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function parseUrlEncodedBody(body) {
  const params = new URLSearchParams(body);
  return Object.fromEntries(params.entries());
}

function normalizeSlackPayload(source) {
  const nestedBody = source.body;

  if (isRecord(nestedBody)) {
    return nestedBody;
  }

  if (typeof nestedBody === 'string' && nestedBody.trim()) {
    const trimmed = nestedBody.trim();

    if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
      try {
        const parsed = JSON.parse(trimmed);
        if (isRecord(parsed)) {
          return parsed;
        }
      } catch {
        // Fall through to urlencoded parsing.
      }
    }

    return parseUrlEncodedBody(trimmed);
  }

  return source;
}

const body = normalizeSlackPayload(input);

// ── URL verification challenge (Slack Event API setup) ────────────────────
if (body.type === 'url_verification') {
  return [{ json: { type: 'challenge', challenge: body.challenge } }];
}

// ── Slash command (application/x-www-form-urlencoded parsed by n8n) ──────
const command = (body.command || '').toLowerCase().trim();
const rawText = (body.text || '').trim();
const channelId = body.channel_id || '';
const userId = body.user_id || '';
const userName = body.user_name || '';
const responseUrl = body.response_url || '';

// Commands that create a new pipeline run
const CREATE_MAP = {
  '/plan': 'planner',
  '/adp-plan': 'planner',
  '/sprint': 'sprint-controller',
  '/adp-sprint': 'sprint-controller',
  '/implement': 'implementer',
  '/adp-implement': 'implementer',
  '/verify': 'verifier',
  '/adp-verify': 'verifier',
};

// Commands that operate on an existing pipeline run
// Text format: /approve <pipeline-id>
// /handoff <pipeline-id> [artifact-path]
const ACTION_MAP = {
  '/approve': 'approve',
  '/adp-approve': 'approve',
  '/takeover': 'takeover',
  '/adp-takeover': 'takeover',
  '/handoff': 'handoff',
  '/adp-handoff': 'handoff',
  '/status': 'status',
  '/adp-status': 'status',
};

if (CREATE_MAP[command]) {
  const parts = rawText.split(/\s+/).filter(Boolean);
  const VALID_MODES = new Set(['next', 'next-flow', 'full-sprint']);
  let executionMode = 'next';
  let description = rawText;

  if (parts.length > 0 && VALID_MODES.has(parts[0])) {
    executionMode = parts[0];
    description = parts.slice(1).join(' ');
  }

  return [{
    json: {
      type: 'create_pipeline',
      entry_point: CREATE_MAP[command],
      execution_mode: executionMode,
      description,
      channel_id: channelId,
      user_id: userId,
      user_name: userName,
      response_url: responseUrl,
    }
  }];
}

if (ACTION_MAP[command]) {
  const parts = rawText.split(' ').filter(Boolean);
  const pipeline_id = parts[0] || '';
  const artifact_path = parts[1] || '';
  return [{
    json: {
      type: 'pipeline_action',
      action: ACTION_MAP[command],
      pipeline_id,
      artifact_path,
      channel_id: channelId,
      user_id: userId,
      user_name: userName,
      response_url: responseUrl,
    }
  }];
}

// Unknown command
return [{
  json: {
    type: 'unknown',
    command,
    response_url: responseUrl,
  }
}];

const pipeline = $input.first().json;
const stepLabel = (pipeline.entry_point || 'planner').replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
const mode = pipeline?.metadata?.execution_mode || 'next';

const lines = [];
lines.push(`\u23F3 Pipeline \`${pipeline.pipeline_id}\` started - running *${stepLabel}*.`);

if (mode === 'next') {
  lines.push('This run may finish quickly in `next` mode (single-step).');
} else {
  lines.push("I'll post an update in this thread when it's ready for review.");
}

lines.push(`Use \`/adp-status ${pipeline.pipeline_id}\` for full status anytime.`);

return [{
  json: {
    response_body: JSON.stringify({
      response_type: 'in_channel',
      text: lines.join('\n')
    })
  }
}];

const data = $input.first().json;
const { action, pipeline_id, artifact_path, user_name, user_id, channel_id } = data;
const actor = user_name || user_id || 'unknown';
const base = $env.EXECUTION_API_BASE_URL;

if (!pipeline_id && action !== 'status') {
  return [{
    json: {
      ...data,
      actor,
      skip_http: true,
      // Keep downstream HTTP node valid; Build Action Ack will emit response_body directly.
      http_method: 'GET',
      http_url: `${base}/health`,
      http_body: null,
      response_body: JSON.stringify({
        response_type: 'ephemeral',
        text: `\u274C Please provide a pipeline ID: \`/${action} <pipeline-id>\``
      })
    }
  }];
}

let method = 'POST';
let url;
let body;

if (action === 'approve') {
  url = `${base}/pipeline/${pipeline_id}/approve`;
  body = JSON.stringify({ actor });
} else if (action === 'takeover') {
  url = `${base}/pipeline/${pipeline_id}/takeover`;
  body = JSON.stringify({ actor });
} else if (action === 'handoff') {
  url = `${base}/pipeline/${pipeline_id}/handoff`;
  body = JSON.stringify({ actor, artifact_path: artifact_path || undefined });
} else if (action === 'status') {
  method = 'GET';
  url = pipeline_id
    ? `${base}/pipeline/${pipeline_id}/status-summary`
    : `${base}/pipeline/status-summary/current?channel_id=${encodeURIComponent(channel_id || '')}`;
  body = null;
}

return [{ json: { ...data, actor, skip_http: false, http_method: method, http_url: url, http_body: body } }];

const result = $input.first().json;
const request = $('Build Action Request').first().json;

if (request.skip_http && request.response_body) {
  return [{ json: { response_body: request.response_body } }];
}

const action = request.action;
const pipeline_id = request.pipeline_id;

let text;
if (action === 'approve') {
  text = `\u2705 Approved - pipeline \`${pipeline_id}\` is advancing.`;
} else if (action === 'takeover') {
  text = `\u270B Takeover confirmed - you now own the current step on \`${pipeline_id}\`.\nUse \`/handoff ${pipeline_id}\` when you're done.`;
} else if (action === 'handoff') {
  text = `\u2705 Handoff complete - pipeline \`${pipeline_id}\` is resuming.`;
} else if (action === 'status') {
  if (result.kind === 'none') {
    text = `\u2139\uFE0F ${result.message}`;
  } else if (result.kind === 'multiple') {
    const fmtRole = r => (r || '').replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
    const statusEmoji = { running: '⏳', complete: '✅', failed: '❌', awaiting_approval: '⏸️', awaiting_pr_review: '👀', paused_takeover: '✋', cancelled: '🚫' };
    const lines = [];
    lines.push('*Multiple active pipelines found in this channel:*');
    lines.push('Use `/adp-status <pipeline-id>` for full details.');
    lines.push('');
    for (const run of (result.runs || [])) {
      const emoji = statusEmoji[run.status] || '❓';
      const repo = run.repo_url ? ` | ${run.repo_url}` : '';
      const branch = run.sprint_branch ? ` | branch: ${run.sprint_branch}` : '';
      const waitState = run.wait_state ? ` | wait: ${run.wait_state}` : '';
      lines.push(`${emoji} \`${run.pipeline_id}\` | ${run.status} | ${fmtRole(run.current_step)}${waitState}${branch}${repo}`);
    }
    text = lines.join('\n');
  } else {
    const run = result.kind === 'single' ? result.run : result;
    const fmtRole = r => (r || '').replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
    const fmtTime = iso => iso ? new Date(iso).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false }) : '-';
    const fmtDuration = (s, e) => (s && e) ? `${Math.round((new Date(e) - new Date(s)) / 1000)}s` : '-';
    const statusEmoji = { running: '⏳', complete: '✅', failed: '❌', awaiting_approval: '⏸️', awaiting_pr_review: '👀', paused_takeover: '✋', cancelled: '🚫' };
    const stepEmoji = { running: '▶️', complete: '✅', failed: '❌', not_applicable: '⬛' };
    const signalEmoji = { waiting: '⏸️', warning: '⚠️', error: '❌' };
    const emoji = statusEmoji[run.status] || '❓';
    const lines = [];
    lines.push(`${emoji} *Pipeline* \`${run.pipeline_id || pipeline_id}\``);
    lines.push(`*Status:* ${run.status}  |  *Active Step:* ${fmtRole(run.current_step)}`);
    if (run.sprint_branch) lines.push(`*Branch:* \`${run.sprint_branch}\``);
    if (run.repo_url) lines.push(`*Repo:* ${run.repo_url}`);
    if (run.pr_url) lines.push(`*PR:* ${run.pr_url}`);
    if (run.implementer_attempts > 0) lines.push(`*Implementer Attempts:* ${run.implementer_attempts}`);

    lines.push('');
    const cur = run.current_step_detail;
    if (cur) {
      lines.push(`*Current Step - ${fmtRole(cur.role)}*`);
      lines.push(`  Status: ${stepEmoji[cur.status] || ''} ${cur.status}  |  Actor: ${cur.actor || '-'}`);
      lines.push(`  Started: ${fmtTime(cur.started_at)}${cur.completed_at ? '  Ended: ' + fmtTime(cur.completed_at) + '  Duration: ' + fmtDuration(cur.started_at, cur.completed_at) : ''}`);
      if (cur.artifact_paths && cur.artifact_paths.length) lines.push(`  Artifacts: ${cur.artifact_paths.join(', ')}`);
    }

    const prior = run.prior_step_detail;
    if (prior) {
      lines.push('');
      lines.push(`*Prior Step - ${fmtRole(prior.role)}*`);
      lines.push(`  Status: ${stepEmoji[prior.status] || ''} ${prior.status}  |  Actor: ${prior.actor || '-'}`);
      lines.push(`  Started: ${fmtTime(prior.started_at)}${prior.completed_at ? '  Ended: ' + fmtTime(prior.completed_at) + '  Duration: ' + fmtDuration(prior.started_at, prior.completed_at) : ''}`);
      if (prior.artifact_paths && prior.artifact_paths.length) lines.push(`  Artifacts: ${prior.artifact_paths.join(', ')}`);
    }

    const signals = Array.isArray(run.execution_signals) ? run.execution_signals : [];
    if (signals.length > 0) {
      lines.push('');
      lines.push('*Execution Signals:*');
      for (const signal of signals) {
        const icon = signalEmoji[signal.level] || 'ℹ️';
        const minutePart = typeof signal.minutes === 'number' ? ` (${signal.minutes}m)` : '';
        lines.push(`  ${icon} [${signal.code}] ${signal.message}${minutePart}`);
      }
    }

    if (run.last_error) {
      lines.push('');
      lines.push(`*Last Error* (${run.last_error.code}): ${run.last_error.message}`);
    }

    lines.push('');
    const stepLine = (run.steps || []).filter(s => s.status !== 'not_applicable').map(s => `${stepEmoji[s.status] || ''}${fmtRole(s.role)}`).join(' -> ');
    lines.push(`*Flow:* ${stepLine}`);
    text = lines.join('\n');
  }
}

return [{ json: { response_body: JSON.stringify({ response_type: 'in_channel', text }) } }];
